const content = $input.first().json.output;

const match = content.match(/<!--\s*filename:\s*(.+?)\s*-->/);
const filename = match ? match[1].trim() : `note-${Date.now()}.md`;

return [{
  json: { filename },
  binary: {
    data: await this.helpers.prepareBinaryData(
      Buffer.from(content, 'utf8'),
      filename,
      'text/markdown'
    )
  }
}];
